select_pipe = SelectPipe.from_dataframe(data)
financial_report = (select_pipe
    | select_numeric()
    | Select(contains('amount'), contains('price'), contains('cost'))
    | AddColumns({
        'profit': lambda df: df['revenue'] - df['cost'],
        'profit_margin': lambda df: (df['revenue'] - df['cost']) / df['revenue']
    })
)
result_df = financial_report.to_df()
